function countAnagramGroups(strs) {
  // For each word, compute a canonical 'signature' that all its anagrams share.
  // Put signatures into a Set. The answer is the Set's size.
  // Sorting letters works as a signature. Counting letters does too (and is faster for long words).
}

solution:
// O(n · k log k) time using sorted-letter signature.
function countAnagramGroups(strs) {
  const signatures = new Set();
  for (const s of strs) {
    signatures.add([...s].sort().join(''));
  }
  return signatures.size;
}

